بخش ۶: حلقه‌ها - تکرار کارها در کد
۱. حلقه for
وقتی تعداد تکرارها مشخص است استفاده می‌شود.
سینتکس:
for (initialization; condition; increment/decrement) {
    // کدی که تکرار می‌شود
}
مثال:
// چاپ اعداد ۱ تا ۵
for (let i = 1; i &lt;= 5; i++) {
    console.log(`تکرار شماره: ${i}`);
}
حلقه for روی آرایه:
const fruits = [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;];
for (let i = 0; i &lt; fruits.length; i++) {
    console.log(fruits[i]);
}
// خروجی: &quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;
۲. حلقه while
وقتی تعداد تکرارها نامشخص است و شرط در ابتدا بررسی می‌شود.
سینتکس:
while (condition) {
    // کدی که تکرار می‌شود
}
مثال:
let count = 1;
while (count &lt;= 3) {
    console.log(`شمارنده: ${count}`);
    count++;
}
// خروجی: &quot;شمارنده: 1&quot;, &quot;شمارنده: 2&quot;, &quot;شمارنده: 3&quot;
خروج از حلقه با break:
let sum = 0;
let number = 1;
while (true) {
    sum += number;
    if (sum &gt; 10) break; // وقتی مجموع از ۱۰ بیشتر شد از حلقه خارج شو
    number++;
}
console.log(`مجموع: ${sum}`);
۳. حلقه do…while
مشابه while، اما حداقل یک بار اجرا می‌شود (شرط در انتها بررسی می‌شود).
سینتکس:
do {
    // کدی که حداقل یک بار اجرا می‌شود
} while (condition);
مثال:
let i = 0;
do {
    console.log(`مقدار i: ${i}`);
    i++;
} while (i &lt; 3);
// خروجی: &quot;مقدار i: 0&quot;, &quot;مقدار i: 1&quot;, &quot;مقدار i: 2&quot;
مثال کاربردی برای دریافت ورودی کاربر:
let password;
do {
    password = prompt(&quot;رمز عبور را وارد کنید:&quot;);
} while (password !== &quot;1234&quot;);
console.log(&quot;رمز عبور صحیح است!&quot;);

