سؤال ۲: انتخاب بهترین گزینه
کدام گزینه برای تعریف هر یک از موارد زیر بهترین گزینه است؟ (const یا let)

الف) شمارنده یک حلقه (Loop Counter)
ب) مقدار PI (عدد ثابت ریاضی)
ج) یک شیء (Object) که قرار است خصوصیات آن در طول برنامه تغییر کند.
د) یک آرایه (Array) که قرار است عناصر جدیدی به آن اضافه شود.

این دو operator ابزارهای اساسی برای تشخیص نوع داده‌ها در زمان اجرا هستند. درک تفاوت و کاربرد صحیح هر یک برای نوشتن کدهای مستحکم ضروری است.
مفاهیم کلیدی:
۱. عملگر typeof:

برای تشخیص نوع اولیه داده‌ها استفاده می‌شود
یک رشته برمی‌گرداند که نوع operand را مشخص می‌کند

// مثال‌های typeof
console.log(typeof &quot;Hello&quot;);        // &quot;string&quot;
console.log(typeof 42);            // &quot;number&quot;
console.log(typeof true);          // &quot;boolean&quot;
console.log(typeof undefined);     // &quot;undefined&quot;
console.log(typeof null);          // &quot;object&quot; (باگ تاریخی!)
console.log(typeof {});            // &quot;object&quot;
console.log(typeof []);            // &quot;object&quot; (مشکل!)
console.log(typeof function() {}); // &quot;function&quot;
console.log(typeof Symbol());      // &quot;symbol&quot;
console.log(typeof 123n);          // &quot;bigint&quot;
محدودیت‌های typeof:

نمی‌تواند بین آرایه و object معمولی تفاوت قائل شود
null را به اشتباه “object” گزارش می‌دهد

۲. عملگر instanceof:

برای بررسی اینکه آیا یک object نمونه‌ای از یک constructor خاص است
زنجیره prototype را بررسی می‌کند

// مثال‌های instanceof
let arr = [1, 2, 3];
console.log(arr instanceof Array);    // true
console.log(arr instanceof Object);   // true (زیرا Array از Object ارث‌بری می‌کند)

let date = new Date();
console.log(date instanceof Date);    // true
console.log(date instanceof Object);  // true

function Person(name) {
    this.name = name;
}
let john = new Person(&quot;John&quot;);
console.log(john instanceof Person);  // true
console.log(john instanceof Object);  // true
