فصل ۹: توابع بازگشتی (Recursive Functions)
یک تابع بازگشتی، تابعی است که خودش را فراخوانی می‌کند. این نوع توابع برای حل مسائلی که می‌توانند به زیرمسائل کوچک‌تر و مشابه تقسیم شوند، عالی هستند.
۹.۱. ساختار یک تابع بازگشتی
هر تابع بازگشتی باید دو بخش داشته باشد:

شرط پایه (Base Case) - شرایطی که بازگشت را متوقف می‌کند
گام بازگشت (Recursive Step) - جایی که تابع خودش را با ورودی کوچک‌تر فراخوانی می‌کند

// مثال: محاسبه فاکتوریل
function factorial(n) {
    // شرط پایه
    if (n === 0 || n === 1) {
        return 1;
    }
    // گام بازگشت
    return n * factorial(n - 1);
}

console.log(factorial(5)); // خروجی: 120
۹.۲. مثال پیچیده‌تر: دنباله فیبوناچی
function fibonacci(n) {
    // شرط پایه
    if (n === 0) return 0;
    if (n === 1) return 1;

    // گام بازگشت
    return fibonacci(n - 1) + fibonacci(n - 2);
}

console.log(fibonacci(6)); // خروجی: 8
۹.۳. بهینه‌سازی با memoization
توابع بازگشتی می‌توانند کند باشند چون محاسبات تکراری انجام می‌دهند. با memoization می‌توانیم سرعت بهینه کنیم:
function memoizedFibonacci() {
    const cache = {};

    return function fib(n) {
        if (n in cache) return cache[n];
        if (n === 0) return 0;
        if (n === 1) return 1;

        cache[n] = fib(n - 1) + fib(n - 2);
        return cache[n];
    };
}

const fib = memoizedFibonacci();
console.log(fib(50)); // خروجی بسیار سریع: 12586269025

فصل ۱۰: توابع تودرتو (Nested Functions)
توابع تودرتو، توابعی هستند که در داخل توابع دیگر تعریف می‌شوند.
۱۰.۱. ویژگی‌های توابع تودرتو

به متغیرهای تابع والد دسترسی دارند (کلوژر)
فقط در داخل تابع والد قابل دسترسی هستند
برای سازماندهی کد و کپسوله‌سازی مفید هستند

function outerFunction(x) {
    let outerVariable = &quot;I&#039;m from outer&quot;;

    // تابع تودرتو
    function innerFunction(y) {
        console.log(outerVariable); // دسترسی به متغیر والد
        console.log(x + y); // دسترسی به پارامتر والد
        return &quot;Inner result&quot;;
    }

    return innerFunction;
}

const inner = outerFunction(10);
console.log(inner(5)); 
// خروجی: 
// I&#039;m from outer
// 15
// Inner result
۱۰.۲. کاربرد عملی: اعتبارسنجی
function createValidator() {
    // توابع تودرتو برای اعتبارسنجی
    function isEmail(value) {
        return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
    }

    function isStrongPassword(value) {
        return value.length &gt;= 8 &amp;&amp; 
               /[A-Z]/.test(value) &amp;&amp; 
               /[0-9]/.test(value);
    }

    // در معرض دید قرار دادن فقط آنچه لازم است
    return {
        validateEmail: function(email) {
            return isEmail(email);
        },
        validatePassword: function(password) {
            return isStrongPassword(password);
        }
    };
}

const validator = createValidator();
console.log(validator.validateEmail(&quot;test@example.com&quot;)); // true
console.log(validator.validatePassword(&quot;Weak&quot;)); // false

ارزیابی فصل ۹ و ۱۰
سوال ۱: تابع بازگشتی بنویس که یک عدد را بگیرد و مجموع اعداد از ۱ تا آن عدد را برگرداند.
سوال ۲: تابعی بنویس که یک آرایه از اعداد را بگیرد و با استفاده از توابع تودرتو، بزرگترین عدد را پیدا کند.
سوال ۳: تفاوت اصلی بین توابع بازگشتی و توابع تودرتو چیست؟ (هر کدام را در یک جمله توضیح بده)
سوال ۴: مشکل تابع فیبوناچی ساده چیست و چگونه memoization آن را حل می‌کند؟
پاسخ‌هایت را برای تکمیل نهایی این فصل منتظرم! این بار واقعاً تمام مباحث مهم را پوشش داده‌ایم! 🌟

تحلیل پاسخ‌های تو:
سوال ۱: تابع بازگشتی جمع اعداد
function sumN(n) {
    if(n === 0) return 0;
    return n + sumN(n - 1);
}

✅ کاملاً درست. شرط پایه و گام بازگشت را به درستی پیاده‌سازی کرده‌ای.
💡 بهینه‌سازی: می‌توانی شرط پایه را به if(n &lt;= 1) return n; تغییر دهی تا برای اعداد منفی هم کار کند.

سوال ۲: تابع پیدا کردن بیشینه‌ی آرایه
function findMax() {
    let max = 0;
    return function(a) {
        max = a[0];
        a.forEach(j =&gt; {if(j &gt; max) max = j; }); 
        return max;
    }
}

✅ ایده خوبی داشتید اما یک مشکل کوچک وجود دارد:

متغیر max در بیرون از تابع داخلی قرار گرفته، اما در هر فراخوانی مجدداً با max = a[0] مقداردهی می‌شود.
این کار باعث می‌شود مزیت کلوژر از بین برود.



راه حل بهینه‌تر:
function createMaxFinder() {
    return function(arr) {
        let max = arr[0];
        for(let i = 1; i &lt; arr.length; i++) {
            if(arr[i] &gt; max) max = arr[i];
        }
        return max;
    }
}

const findMax = createMaxFinder();
console.log(findMax([3,10,7,40,1])); // خروجی: 40
سوال ۳: تفاوت توابع بازگشتی و تودرتو
پاسخ تو: “در توابع بازگشتی یک تابع در درون خودش خود را فرامی خواند. شرط خاتمه تکرار فراخوانی باید در تابع پیش بینی شود. اما در توابع تودرتو یک تابع در درون خود یک تابع دیگر را تعریف می کند اشاره گر به آن را به فراخواننده باز می گرداند.”

✅ تحلیل: این تعریف بسیار دقیق و حرفه‌ای است!

بازگشتی: خود-فراخوانی با شرط توقف
تودرتو: تعریف تابع داخلی و بازگرداندن آن



سوال ۴: مشکل فیبوناچی و راه حل Memoization
// مشکل: محاسبات تکراری
fibonacci(5) = fibonacci(4) + fibonacci(3)
// fibonacci(4) خودش fibonacci(3) + fibonacci(2) را محاسبه می‌کند
// بنابراین fibonacci(3) دو بار محاسبه می‌شود!

// راه حل: ذخیره نتایج محاسبات قبلی
function memoizedFibonacci() {
    const cache = {};

    return function fib(n) {
        if(n in cache) return cache[n]; // اگر قبلاً حساب شده، برگردان
        if(n &lt;= 1) return n;

        cache[n] = fib(n-1) + fib(n-2); // ذخیره نتیجه
        return cache[n];
    };
}

🎉 تبریک! اکنون واقعاً فصل “توابع و Scope” را کامل کردی!
