🎯 ادامه مبحث: پیمایش در ویژگی‌های شیء
حالا که با دسترسی به ویژگی‌ها مسلط شدید، بیایید روش‌های پیمایش بین تمام ویژگی‌های یک شیء را بررسی کنیم:
۱. حلقه for...in
let person = {
    name: &quot;علی&quot;,
    age: 30,
    city: &quot;تهران&quot;
};

for (let key in person) {
    console.log(`${key}: ${person[key]}`);
}
۲. Object.keys()
let keys = Object.keys(person);
console.log(keys); // [&quot;name&quot;, &quot;age&quot;, &quot;city&quot;]
۳. Object.values()
let values = Object.values(person);
console.log(values); // [&quot;علی&quot;, 30, &quot;تهران&quot;]
۴. Object.entries()
let entries = Object.entries(person);
console.log(entries); // [[&quot;name&quot;, &quot;علی&quot;], [&quot;age&quot;, 30], [&quot;city&quot;, &quot;تهران&quot;]]

