🎯 مبحث بعدی: آرایه‌ها (Arrays)
حالا که به طور کامل بر شیءها مسلط شدیم، به سراغ یکی از مهم‌ترین ساختمان‌داده‌ها در جاوااسکریپت می‌رویم: آرایه‌ها
تعریف آرایه
آرایه‌ها برای ذخیره‌سازی مجموعه‌ای از مقادیر در یک متغیر استفاده می‌شوند.
let fruits = [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;];
let numbers = [1, 2, 3, 4, 5];
