🎯 ادامه مباحث پیشرفته: مشکلات رایج در کار با شیءها
مشکلات رایج (Common Pitfalls)
۱. دسترسی به ویژگی‌های ناموجود
let obj = { a: 1 };
console.log(obj.b); // undefined (خطا نمی‌دهد)
۲. بازنویسی ناخواسته ویژگی‌ها
let obj = { a: 1 };
obj.a = 2; // مقدار قبلی overwrite می‌شود
console.log(obj.a); // 2
۳. تغییر ناخواسته به دلیل ارجاع (Reference)
function modify(obj) {
    obj.a = 100; // شیء اصلی تغییر می‌کند!
}

let myObj = { a: 1 };
modify(myObj);
console.log(myObj.a); // 100 (مقدار اصلی تغییر کرد)

