let config = {
    theme: &quot;dark&quot;,
    version: 1.0
};

let userSettings = config;
userSettings.theme = &quot;light&quot;;

console.log(config.theme); // چه چیزی چاپ می‌شود؟ چرا؟
سؤال ۲: چگونه می‌توان از تغییر ناخواسته در مثال بالا جلوگیری کرد؟
