✅ دلیل آن را درست تشخیص دادید: اشتراک ارجاع (Reference) بین دو متغیر
✅ راه حل را به درستی شناسایی کردید: ایجاد کپی جدید


🛠 راه حل‌های عملی برای جلوگیری از تغییر ناخواسته
۱. کپی سطحی (Shallow Copy)
// روش‌های ایجاد کپی سطحی
let userSettings1 = Object.assign({}, config);
let userSettings2 = { ...config }; // Spread Operator (روش مدرن)

userSettings1.theme = &quot;light&quot;;
console.log(config.theme); // &quot;dark&quot; (تغییر نکرد!)
۲. کپی عمیق (Deep Copy) - برای شیءهای پیچیده
// برای شیءهای با سطوح تو در تو
let config = {
    theme: &quot;dark&quot;,
    settings: {
        fontSize: 14,
        language: &quot;fa&quot;
    }
};

let userSettings = JSON.parse(JSON.stringify(config)); // کپی عمیق
userSettings.settings.fontSize = 16;

console.log(config.settings.fontSize); // 14 (تغییر نکرد!)

