آماده‌اید برای حرکت به سراغ مبحث جذاب “متدها” (Methods)؟
در این بخش یاد می‌گیریم:

تعریف توابع داخل شیءها
کار با کلمه کلیدی this
متدهای built-in شیءها

پاسخ دهید تا این مبحث مهم را شروع کنیم.
عالی! حالا به سراغ مبحث جذاب “متدها” (Methods) می‌رویم.
🎯 متدها: توابع داخل شیءها (Methods: Functions Inside Objects)
متدها در واقع توابعی هستند که به عنوان ویژگی یک شیء تعریف می‌شوند و به شیء امکان انجام عملیات می‌دهند.
۱. تعریف متدها
let person = {
    firstName: &quot;نازنین&quot;,
    lastName: &quot;احمدی&quot;,

    // تعریف متد با function
    getFullName: function() {
        return this.firstName + &quot; &quot; + this.lastName;
    },

    // تعریف متد با سینتکس ES6 (کوتاه‌تر)
    greet() {
        return `سلام، من ${this.firstName} هستم!`;
    }
};

console.log(person.getFullName()); // &quot;نازنین احمدی&quot;
console.log(person.greet()); // &quot;سلام، من نازنین هستم!&quot;
۲. کلمه کلیدی this در متدها
this به شیءای اشاره می‌کند که متد را فراخوانی کرده است.
let car = {
    brand: &quot;تویوتا&quot;,
    model: &quot;کمری&quot;,

    displayInfo() {
        return `این ماشین یک ${this.brand} ${this.model} است.`;
    }
};

console.log(car.displayInfo()); // &quot;این ماشین یک تویوتا کمری است.&quot;
۳. افزودن متد به صورت پویا
let calculator = {};

// افزودن متد پس از ایجاد شیء
calculator.add = function(a, b) {
    return a + b;
};

calculator.multiply = function(a, b) {
    return a * b;
};

console.log(calculator.add(5, 3)); // 8

