🎯 مبحث پیشرفته: زنجیره‌سازی متدها (Method Chaining)
یک تکنیک حرفه‌ای که به شما امکان می‌دهد چندین متد را پشت سر هم فراخوانی کنید:
let calculator = {
    result: 0,

    add(value) {
        this.result += value;
        return this; // بازگرداندن خود شیء برای زنجیره‌سازی
    },

    subtract(value) {
        this.result -= value;
        return this;
    },

    multiply(value) {
        this.result *= value;
        return this;
    },

    getResult() {
        return this.result;
    }
};

// استفاده از زنجیره‌سازی متدها
let finalResult = calculator.add(5).subtract(2).multiply(3).getResult();
console.log(finalResult); // 9

⚠️ هشدار مهم: arrow functions در متدها
// ❌ اشتباه - استفاده از arrow function در متد
const person = {
    name: &quot;سارا&quot;,
    greet: () =&gt; {
        console.log(`سلام، من ${this.name} هستم`);
    }
};
person.greet(); // &quot;سلام، من undefined هستم&quot;

// ✅ درست - استفاده از تابع معمولی
const person = {
    name: &quot;سارا&quot;,
    greet() {
        console.log(`سلام، من ${this.name} هستم`);
    }
};
person.greet(); // &quot;سلام، من سارا هستم&quot;

