🎯 Iterating Over Methods (پیمایش بر روی متدها)
این مبحث درباره چگونگی تشخیص و اجرای متدهای موجود در یک شیء است.
۱. تشخیص متدها در شیء
از typeof برای تشخیص اینکه یک ویژگی، تابع/متد است استفاده می‌کنیم:
let person = {
    name: &quot;سارا&quot;,
    age: 30,
    greet() {
        return &quot;سلام!&quot;;
    },
    sayGoodbye() {
        return &quot;خداحافظ!&quot;;
    }
};

// پیمایش بر روی تمام ویژگی‌های شیء
for (let key in person) {
    if (typeof person[key] === &#039;function&#039;) {
        console.log(`${key} یک متد است: ${person[key]()}`);
    }
}
خروجی:
greet یک متد است: سلام!
sayGoodbye یک متد است: خداحافظ!

۲. استفاده از Object.keys همراه با forEach
let calculator = {
    result: 0,
    add(x) { this.result += x; },
    subtract(x) { this.result -= x; },
    getResult() { return this.result; }
};

Object.keys(calculator).forEach(key =&gt; {
    if (typeof calculator[key] === &#039;function&#039;) {
        console.log(`متد پیدا شد: ${key}`);
    }
});
۳. مثال کاربردی از کتاب
let obj = {
    name: &quot;رویا&quot;,
    greet() {
        return &quot;سلام!&quot;;
    },
    farewell() {
        return &quot;خداحافظ!&quot;;
    }
};

for (let key in obj) {
    if (typeof obj[key] === &#039;function&#039;) {
        console.log(`${key}: ${obj[key]()}`);
    }
}

