🎯 کاربردهای عملی پیمایش متدها
۱. ثبت خودکار لاگ از تمام متدها
let apiService = {
    getUsers() { return &quot;لیست کاربران&quot;; },
    createUser() { return &quot;کاربر ایجاد شد&quot;; },
    deleteUser() { return &quot;کاربر حذف شد&quot;; }
};

// ایجاد لاگر خودکار برای تمام متدها
Object.keys(apiService).forEach(key =&gt; {
    if (typeof apiService[key] === &#039;function&#039;) {
        const originalMethod = apiService[key];
        apiService[key] = function(...args) {
            console.log(`متد ${key} فراخوانی شد`);
            return originalMethod.apply(this, args);
        };
    }
});

apiService.getUsers(); // &quot;متد getUsers فراخوانی شد&quot;
۲. ساخت سیستم پلاگین
let app = {
    plugins: [],
    registerPlugin(plugin) {
        if (typeof plugin === &#039;function&#039;) {
            this.plugins.push(plugin);
        }
    },
    runAllPlugins() {
        this.plugins.forEach(plugin =&gt; {
            if (typeof plugin === &#039;function&#039;) {
                plugin();
            }
        });
    }
};

