🎯 ادامه مبحث this در موقعیت‌های پیشرفته
۵. this در توابع تو در تو (Nested Functions)
let person = {
    name: &quot;زهرا&quot;,
    greet: function() {
        function innerGreet() {
            return `سلام، من ${this.name} هستم`;
