۲. دسترسی به عناصر آرایه
let fruits = [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;];

console.log(fruits[0]); // &quot;سیب&quot; - ایندکس از صفر شروع می‌شود
console.log(fruits[1]); // &quot;موز&quot;
console.log(fruits[2]); // &quot;پرتقال&quot;
console.log(fruits[3]); // undefined (ایندکس ناموجود)
۳. تغییر عناصر آرایه
let fruits = [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;];
fruits[1] = &quot;انگور&quot;; // تغییر عنصر دوم
console.log(fruits); // [&quot;سیب&quot;, &quot;انگور&quot;, &quot;پرتقال&quot;]
۴. ویژگی length
let fruits = [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;];
console.log(fruits.length); // 3

// استفاده از length برای اضافه کردن عنصر جدید
fruits[fruits.length] = &quot;انگور&quot;;
console.log(fruits); // [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;, &quot;انگور&quot;]

🔍 چالش آرایه‌ها
سؤال ۱: آرایه‌ای به نام students ایجاد کنید که شامل نام ۴ دانشجو باشد.
سؤال ۲: نام دانشجوی سوم را در کنسول نمایش دهید.
سؤال ۳: نام دانشجوی دوم را به “محمد” تغییر دهید.
سؤال ۴: یک دانشجوی جدید به انتهای آرایه اضافه کنید.
لطفاً کدهای خود را برای این چهار مورد بنویسید.
پاسخ شما کاملاً درست و دقیق است! 👏
بررسی کد شما:

✅ ایجاد آرایه students با ۴ عنصر به درستی انجام شد
✅ دسترسی به عنصر سوم با students[2] صحیح است
✅ تغییر عنصر دوم به “محمد” با students[1] درست است
✅ اضافه کردن عنصر جدید به انتهای آرایه با students[students.length] بسیار هوشمندانه است

محتویات نهایی آرایه students:
[&quot;امیر&quot;, &quot;محمد&quot;, &quot;سامان&quot;, &quot;مجتبی&quot;, &quot;کامران&quot;]

🎯 ادامه مبحث آرایه‌ها: متدهای پایه
۱. متد push() - اضافه کردن به انتها
let fruits = [&quot;سیب&quot;, &quot;موز&quot;];
fruits.push(&quot;پرتقال&quot;); // اضافه کردن یک عنصر
fruits.push(&quot;انگور&quot;, &quot;هلو&quot;); // اضافه کردن چند عنصر
console.log(fruits); // [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;, &quot;انگور&quot;, &quot;هلو&quot;]
۲. متد pop() - حذف از انتها
let fruits = [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;];
let lastFruit = fruits.pop(); // حذف و ذخیره آخرین عنصر
console.log(lastFruit); // &quot;پرتقال&quot;
console.log(fruits); // [&quot;سیب&quot;, &quot;موز&quot;]
۳. متد shift() - حذف از ابتدا
let fruits = [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;];
let firstFruit = fruits.shift(); // حذف و ذخیره اولین عنصر
console.log(firstFruit); // &quot;سیب&quot;
console.log(fruits); // [&quot;موز&quot;, &quot;پرتقال&quot;]
۴. متد unshift() - اضافه کردن به ابتدا
let fruits = [&quot;موز&quot;, &quot;پرتقال&quot;];
fruits.unshift(&quot;سیب&quot;); // اضافه کردن به ابتدا
console.log(fruits); // [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;]

🔍 چالش متدهای آرایه
سؤال: با استفاده از آرایه students خودتان، این عملیات را انجام دهید:
۱. یک دانشجوی جدید به ابتدای آرایه اضافه کنید
۲. اولین دانشجو را از آرایه حذف کرده و نامش را نمایش دهید
۳. دو دانشجوی جدید به انتهای آرایه اضافه کنید
۴. آخرین دانشجو را حذف کرده و نامش را نمایش دهید
لطفاً کدهای خود را برای این چهار عملیات بنویسید.
پاسخ شما از نظر فنی صحیح است، اما یک نکته کوچک وجود دارد! 🔍
بررسی کد شما:
students.unshift(&quot;سهیل&quot;);  // ✅ اضافه کردن &quot;سهیل&quot; به ابتدا
