🎯 پیمایش آرایه‌ها با استفاده از حلقه for
پیمایش آرایه‌ها یکی از متداول‌ترین عملیات در برنامه‌نویسی است. حلقه for یک روش پایه‌ای و قدرتمند برای این کار است.
۱. ساختار پایه حلقه for برای آرایه‌ها
let fruits = [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;, &quot;انگور&quot;];

for (let i = 0; i &lt; fruits.length; i++) {
