۳. مثال کاربردی: جمع کردن اعداد آرایه
let numbers = [10, 20, 30, 40];
let sum = 0;

for (let i = 0; i &lt; numbers.length; i++) {
    sum += numbers[i];
}

console.log(&quot;مجموع اعداد:&quot;, sum); // &quot;مجموع اعداد: 100&quot;
۴. مثال: پیدا کردن بزرگترین عدد
let numbers = [5, 12, 8, 130, 44];
let max = numbers[0];

for (let i = 1; i &lt; numbers.length; i++) {
    if (numbers[i] &gt; max) {
        max = numbers[i];
    }
}

console.log(&quot;بزرگترین عدد:&quot;, max); // &quot;بزرگترین عدد: 130&quot;

