آماده‌اید برای تمرین‌های پایانی این فصل و تست دانش خود باشید؟
بسیار عالی! حالا به سراغ مبحث مهم “متدهای آرایه” می‌رویم:
🎯 Array Methods: push, pop, slice, and splice
این متدها برای مدیریت و دستکاری آرایه‌ها بسیار ضروری هستند.
۱. متد push()

کاربرد: اضافه کردن یک یا چند عنصر به انتهای آرایه
مقدار بازگشتی: طول جدید آرایه
تغییر در آرایه اصلی: ✅ (آرایه را تغییر می‌دهد)

let fruits = [&quot;سیب&quot;, &quot;موز&quot;];

let newLength = fruits.push(&quot;پرتقال&quot;);
console.log(fruits); // [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;]
console.log(newLength); // 3

// اضافه کردن چند عنصر
fruits.push(&quot;انگور&quot;, &quot;هلو&quot;);
console.log(fruits); // [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;, &quot;انگور&quot;, &quot;هلو&quot;]
۲. متد pop()

کاربرد: حذف آخرین عنصر از آرایه
مقدار بازگشتی: عنصر حذف شده
تغییر در آرایه اصلی: ✅

let fruits = [&quot;سیب&quot;, &quot;موز&quot;, &quot;پرتقال&quot;];

let lastFruit = fruits.pop();
console.log(lastFruit); // &quot;پرتقال&quot;
console.log(fruits); // [&quot;سیب&quot;, &quot;موز&quot;]

// روی آرایه خالی
let emptyArray = [];
let result = emptyArray.pop();
console.log(result); // undefined

