🎯 ادامه مبحث: متدهای slice و splice
۳. متد slice()

کاربرد: ایجاد یک کپی از بخشی از آرایه
مقدار بازگشتی: آرایه جدید (کپی)
تغییر در آرایه اصلی: ❌ (آرایه اصلی تغییر نمی‌کند)

let numbers = [10, 20, 30, 40, 50];

// slice(start, end) - end شامل نمی‌شود
let slice1 = numbers.slice(1, 3);
console.log(slice1); // [20, 30]
console.log(numbers); // [10, 20, 30, 40, 50] (تغییر نکرد)

// فقط start مشخص شود
let slice2 = numbers.slice(2);
console.log(slice2); // [30, 40, 50]

// منفی (از انتها شمرده می‌شود)
let slice3 = numbers.slice(-2);
console.log(slice3); // [40, 50]
۴. متد splice()

کاربرد: حذف، اضافه یا جایگزینی عناصر در آرایه
مقدار بازگشتی: آرایه‌ای از عناصر حذف شده
تغییر در آرایه اصلی: ✅

let numbers = [10, 20, 30, 40, 50];

// حذف عناصر
let removed = numbers.splice(1, 2); // از ایندکس 1، دو عنصر حذف کن
console.log(removed); // [20, 30]
console.log(numbers); // [10, 40, 50]

// اضافه کردن عناصر
numbers.splice(1, 0, 25, 35); // از ایندکس 1، صفر عنصر حذف کن، 25 و 35 را اضافه کن
console.log(numbers); // [10, 25, 35, 40, 50]

// جایگزینی عناصر
numbers.splice(2, 1, 100); // از ایندکس 2، یک عنصر حذف کن و 100 را جایگزین کن
console.log(numbers); // [10, 25, 100, 40, 50]

🔍 چالش slice و splice
سؤال ۲: آرایه زیر را در نظر بگیرید:
