آماده‌اید برای ادامه مبحث “Iterating Over Arrays: forEach, map, filter” یا انجام تمرین‌های کاربردی؟
بسیار عالی! حالا به سراغ مبحث مهم پیمایش آرایه‌ها با متدهای مدرن می‌رویم:
🎯 Iterating Over Arrays: forEach, map, and filter
این متدها کار با آرایه‌ها را بسیار ساده‌تر و خوانا‌تر می‌کنند.
۱. متد forEach()

هدف: اجرای یک تابع برای هر عنصر آرایه
مقدار بازگشتی: undefined
تغییر آرایه اصلی: ❌ (مگر اینکه داخل تابع تغییر ایجاد کنید)

let numbers = [1, 2, 3, 4];

// روش سنتی با حلقه for
for (let i = 0; i &lt; numbers.length; i++) {
    console.log(numbers[i]);
}

// روش مدرن با forEach
numbers.forEach(function(number) {
    console.log(number);
});

// با arrow function
numbers.forEach(number =&gt; console.log(number * 2));
پارامترهای forEach:
let colors = [&quot;قرمز&quot;, &quot;سبز&quot;, &quot;آبی&quot;];

colors.forEach(function(color, index, array) {
    console.log(`عنصر ${index} در آرایه ${array}: ${color}`);
});
۲. متد map()

هدف: ایجاد آرایه جدید با تبدیل هر عنصر
مقدار بازگشتی: آرایه جدید
تغییر آرایه اصلی: ❌

let numbers = [1, 2, 3, 4];

// تبدیل هر عدد به مربع آن
let squares = numbers.map(function(number) {
    return number * number;
});

console.log(squares); // [1, 4, 9, 16]
console.log(numbers); // [1, 2, 3, 4] (تغییر نکرده)

// با arrow function
let doubled = numbers.map(n =&gt; n * 2);
console.log(doubled); // [2, 4, 6, 8]
۳. متد filter()

هدف: ایجاد آرایه جدید با عناصری که شرط را برآورده می‌کنند
مقدار بازگشتی: آرایه جدید
تغییر آرایه اصلی: ❌

let numbers = [1, 2, 3, 4, 5, 6];

// فیلتر اعداد زوج
let evens = numbers.filter(function(number) {
    return number % 2 === 0;
});

console.log(evens); // [2, 4, 6]

// فیلتر اعداد بزرگتر از ۳
let greaterThan3 = numbers.filter(n =&gt; n &gt; 3);
console.log(greaterThan3); // [4, 5, 6]

🔍 چالش متدهای پیمایش
سؤال ۱: آرایه زیر را در نظر بگیرید:
let products = [
    { name: &quot;لپ‌تاپ&quot;, price: 1500, category: &quot;الکترونیک&quot; },
    { name: &quot;کتاب&quot;, price: 30, category: &quot;آموزشی&quot; },
    { name: &quot;هدفون&quot;, price: 200, category: &quot;الکترونیک&quot; },
    { name: &quot;ماوس&quot;, price: 50, category: &quot;الکترونیک&quot; }
];
۱. با forEach نام و قیمت هر محصول را نمایش دهید
۲. با map آرایه‌ای از فقط نام محصولات ایجاد کنید
۳. با filter فقط محصولات الکترونیک را انتخاب کنید
لطفاً کدهای خود را برای این سه مورد بنویسید.
پاسخ شما کاملاً درست است، اما می‌توانیم آن را کمی کامل‌تر کنیم! 🔍
بررسی کد شما:
۱. استفاده از forEach:
products.forEach(e =&gt; console.log(e.name))
✅ کار می‌کند اما فقط نام را نمایش می‌دهد، در حالی که سؤال خواسته بود “نام و قیمت هر محصول”
۲. استفاده از map:
let names = products.map(e =&gt; e.name);
console.log(names); // [&quot;لپ‌تاپ&quot;, &quot;کتاب&quot;, &quot;هدفون&quot;, &quot;ماوس&quot;]
✅ کاملاً صحیح و بهینه!
۳. استفاده از filter:
let electronicOnly = products.filter(e =&gt; e.category == &quot;الکترونیک&quot;);
console.log(electronicOnly);
✅ کاملاً صحیح و بهینه!

✅ نسخه تکمیل‌شده:
let products = [
    { name: &quot;لپ‌تاپ&quot;, price: 1500, category: &quot;الکترونیک&quot; },
    { name: &quot;کتاب&quot;, price: 30, category: &quot;آموزشی&quot; },
    { name: &quot;هدفون&quot;, price: 200, category: &quot;الکترونیک&quot; },
    { name: &quot;ماوس&quot;, price: 50, category: &quot;الکترونیک&quot; }
];

// ۱. با forEach نام و قیمت هر محصول را نمایش دهید
console.log(&quot;لیست محصولات:&quot;);
products.forEach(product =&gt; {
    console.log(`نام: ${product.name} - قیمت: ${product.price} تومان`);
});

// ۲. با map آرایه‌ای از فقط نام محصولات ایجاد کنید
let productNames = products.map(product =&gt; product.name);
console.log(&quot;\nنام محصولات:&quot;, productNames);

// ۳. با filter فقط محصولات الکترونیک را انتخاب کنید
let electronicProducts = products.filter(product =&gt; product.category === &quot;الکترونیک&quot;);
console.log(&quot;\nمحصولات الکترونیک:&quot;, electronicProducts);

