🔍 کاربردهای واقعی Chaining (زنجیره‌سازی)
مثال ۱: پردازش داده کاربران
let users = [
    { name: &quot;علی&quot;, age: 25, active: true },
    { name: &quot;سارا&quot;, age: 17, active: true },
    { name: &quot;محمد&quot;, age: 30, active: false },
    { name: &quot;فاطمه&quot;, age: 22, active: true }
];

// کاربران فعال بالای ۱۸ سال
let activeAdults = users
    .filter(user =&gt; user.active)          // فقط کاربران فعال
    .filter(user =&gt; user.age &gt;= 18)       // فقط بالای ۱۸ سال
    .map(user =&gt; user.name);              // فقط نام آنها

console.log(activeAdults); // [&quot;علی&quot;, &quot;فاطمه&quot;]
مثال ۲: محاسبات مالی
let transactions = [100, -50, 200, -30, 150, -20];

// مجموع درآمدهای مثبت
let totalIncome = transactions
    .filter(amount =&gt; amount &gt; 0)         // فقط درآمدها
    .reduce((sum, amount) =&gt; sum + amount, 0); // جمع آنها

console.log(&quot;کل درآمد:&quot;, totalIncome); // 450

