بیایید دقیقاً به این مبحث برگردیم و آن را کامل بررسی کنیم:
🎯 Multidimensional Arrays and Nested Objects
بخش ۱: آرایه‌های چندبعدی (Multidimensional Arrays)
آرایه‌ای که شامل آرایه‌های دیگر است - مانند یک جدول یا ماتریس.
ایجاد و دسترسی:
// ماتریس 3x3 (3 سطر، 3 ستون)
let matrix = [
    [1, 2, 3],   // سطر 0
    [4, 5, 6],   // سطر 1
    [7, 8, 9]    // سطر 2
];

// دسترسی به عناصر
console.log(matrix[0][0]); // 1 (سطر 0، ستون 0)
console.log(matrix[1][2]); // 6 (سطر 1، ستون 2)
console.log(matrix[2][1]); // 8 (سطر 2، ستون 1)
پیمایش با حلقه‌های تودرتو:
let matrix = [
    [1, 2, 3],
    [4, 5, 6],
    [7, 8, 9]
];

// پیمایش سطرها
for (let row = 0; row &lt; matrix.length; row++) {
    // پیمایش ستون‌های هر سطر
    for (let col = 0; col &lt; matrix[row].length; col++) {
        console.log(`[${row}][${col}] = ${matrix[row][col]}`);
    }
}
کاربرد عملی: بازی دوز (Tic Tac Toe)
let ticTacToe = [
