بخش ۲: شیءهای تو در تو (Nested Objects)
شیءهایی که شامل شیءهای دیگر به عنوان ویژگی هستند.
ایجاد و دسترسی:
let university = {
    name: &quot;دانشگاه تهران&quot;,
    location: {
        city: &quot;تهران&quot;,
        country: &quot;ایران&quot;,
        address: {
            street: &quot;انقلاب&quot;,
            number: 16
        }
    },
    departments: {
        engineering: {
            head: &quot;دکتر احمدی&quot;,
            students: 500
        },
        science: {
            head: &quot;دکتر محمدی&quot;, 
            students: 300
        }
    }
};

// دسترسی به ویژگی‌های تو در تو
console.log(university.location.city); // &quot;تهران&quot;
console.log(university.departments.engineering.head); // &quot;دکتر احمدی&quot;
console.log(university.departments.science.students); // 300
تغییر و افزودن:
// تغییر مقدار
university.departments.engineering.students = 550;

// افزودن بخش جدید
university.departments.arts = {
    head: &quot;دکتر رضایی&quot;,
    students: 200
};

// دسترسی با bracket notation
let dept = &quot;science&quot;;
console.log(university.departments[dept].head); // &quot;دکتر محمدی&quot;

بخش ۳: ترکیب آرایه و شیء
مثال: سیستم دانشجویی
let students = [
    {
        id: 1,
        name: &quot;علی رضایی&quot;,
        grades: {
            math: 18,
            physics: 17,
            programming: 19
        }
    },
    {
        id: 2, 
        name: &quot;سارا محمدی&quot;,
        grades: {
            math: 19,
            physics: 16,
            programming: 20
        }
    }
];

// دسترسی به داده‌ها
console.log(students[0].name); // &quot;علی رضایی&quot;
console.log(students[1].grades.programming); // 20

// محاسبه میانگین نمرات یک دانشجو
let aliAverage = (students[0].grades.math + 
                  students[0].grades.physics + 
                  students[0].grades.programming) / 3;
console.log(&quot;میانگین علی:&quot;, aliAverage.toFixed(2));

🔍 چالش ترکیبی
سؤال: ساختار داده زیر را در نظر بگیرید:
let school = {
    name: &quot;دبیرستان نمونه&quot;,
    classes: [
        {
            grade: &quot;دهم&quot;,
            students: [
                { name: &quot;علی&quot;, score: 18 },
                { name: &quot;سارا&quot;, score: 19 }
            ]
        },
        {
            grade: &quot;یازدهم&quot;, 
            students: [
                { name: &quot;محمد&quot;, score: 17 },
                { name: &quot;فاطمه&quot;, score: 20 }
            ]
        }
    ]
};
۱. نام مدرسه را نمایش دهید.
۲. نمره سارا (در کلاس دهم) را نمایش دهید.
۳. یک دانشجوی جدید به کلاس یازدهم اضافه کنید.
۴. میانگین نمرات کلاس دهم را محاسبه کنید.
لطفاً کدهای خود را برای این چهار مورد بنویسید.
پاسخ شما کاملاً درست و حرفه‌ای است! 👏
بررسی دقیق کد شما:
۱. نمایش نام مدرسه:
console.log(school.name); // &quot;دبیرستان نمونه&quot; ✅
۲. نمره سارا:
console.log(school.classes[0].students[1].score); // 19 ✅

classes[0]: کلاس دهم (ایندکس 0)
students[1]: دانشجوی دوم (سارا)
score: نمره سارا

۳. اضافه کردن دانشجوی جدید:
school.classes[1].students.push({name:&quot;کریم&quot;,score:18}); ✅

classes[1]: کلاس یازدهم
students.push(): اضافه کردن به آرایه دانشجویان

۴. محاسبه میانگین نمرات کلاس دهم:
let sum = 0;
school.classes[0].students.forEach(e =&gt; sum += e.score);
console.log(sum / school.classes[0].students.length); // 18.5 ✅
محاسبه: (18 + 19) / 2 = 18.5

✅ ساختار نهایی داده‌ها پس از اجرای کد شما:
{
    name: &quot;دبیرستان نمونه&quot;,
    classes: [
        {
            grade: &quot;دهم&quot;,
            students: [
                { name: &quot;علی&quot;, score: 18 },
                { name: &quot;سارا&quot;, score: 19 }
            ]
        },
        {
            grade: &quot;یازدهم&quot;,
            students: [
                { name: &quot;محمد&quot;, score: 17 },
                { name: &quot;فاطمه&quot;, score: 20 },
                { name: &quot;کریم&quot;, score: 18 } // ✅ دانشجوی جدید اضافه شده
            ]
        }
    ]
}

🎯 نکات برجسته از کد شما:


درک عمیق ایندکس‌گذاری: شما به درستی از ایندکس‌های عددی برای آرایه‌ها ([0], [1]) و نام‌های ویژگی برای شیءها (.name, .score) استفاده کردید.


تسلط بر روش‌های آرایه: استفاده هوشمندانه از push() برای افزودن و forEach() برای محاسبه مجموع.


کار با ساختارهای پیچیده: توانستید در یک ساختار ۴ لایه تو در تو (school.classes[0].students[1].score) به راحتی حرکت کنید.


محاسبات دقیق: میانگین را به درستی با تقسیم مجموع بر تعداد محاسبه کردید.



